const body = $input.first().json.body || $input.first().json;

// VAPI sends different event types - we only want 'end-of-call-report'
const eventType = body.message?.type || body.type || '';

if (eventType !== 'end-of-call-report') {
  return [{ json: { skip: true, eventType } }];
}

const message = body.message || body;

// Extract core call data
const callData = message.call || {};
const artifact = message.artifact || {};
const analysis = message.analysis || {};

// Extract transcript
const transcript = artifact.transcript || 'No transcript available';

// Extract duration
const startTime = callData.startedAt || callData.createdAt || '';
const endTime = callData.endedAt || '';
let duration = 'N/A';
if (startTime && endTime) {
  const secs = Math.round((new Date(endTime) - new Date(startTime)) / 1000);
  duration = `${Math.floor(secs/60)}m ${secs%60}s`;
}

// Extract ended reason
const endedReason = callData.endedReason || message.endedReason || 'Unknown';

// Extract customer name
const customerName = callData.customer?.name || 'Unknown';

// Extract recording URL
const recordingUrl = artifact.recordingUrl || 'Not available';

// Determine qualification status from transcript
const transcriptLower = transcript.toLowerCase();
let qualificationStatus = 'Not Qualified';
let callbackBooked = 'No';

if (transcriptLower.includes('callback') || 
    transcriptLower.includes('schedule') || 
    transcriptLower.includes('appointment') ||
    transcriptLower.includes('tomorrow') ||
    transcriptLower.includes('time works')) {
  qualificationStatus = 'Qualified';
  callbackBooked = 'Yes';
} else if (transcriptLower.includes('budget') || 
           transcriptLower.includes('timeline') ||
           transcriptLower.includes('looking to buy') ||
           transcriptLower.includes('looking to sell')) {
  qualificationStatus = 'Partial';
}

if (transcriptLower.includes('not interested') || 
    transcriptLower.includes('remove me') ||
    transcriptLower.includes('dont call')) {
  qualificationStatus = 'Not Interested';
  callbackBooked = 'No';
}

return [{
  json: {
    skip: false,
    timestamp: new Date().toLocaleString('en-PK', { timeZone: 'Asia/Karachi' }),
    customerName,
    callDuration: duration,
    endedReason,
    qualificationStatus,
    callbackBooked,
    fullTranscript: transcript,
    recordingUrl
  }
}];
